#include <bits/stdc++.h>
using namespace std;

const long long MOD = 1000000007;

void solve(long long N, std::string S){
    long long res = 1;
    if(S[0]!='B'){
        cout<<0<<endl;
        return;
    }
    long long k=1;
    for(int i=1;i<2*N;++i){
        if((S[i]=='B')^(k%2==1)){
            k++;
        }
        else{
            res*=k;
            res%=MOD;
            k--;
        }
    }
    for(long long t=1;t<=N;++t){
        res*=t;
        res%=MOD;
    }
    if(k!=0){
        cout<<0<<endl;
        return;
    }
    cout<<res<<endl;
}

// Generated by 1.1.4 https://github.com/kyuridenamida/atcoder-tools  (tips: You use the default template now. You can remove this line by using your custom template)
int main(){
    long long N;
    scanf("%lld",&N);
    std::string S;
    std::cin >> S;
    solve(N, S);
    return 0;
}
